const input = $json.formattedDate; // "02-04-2025 11:43"

// Separar la fecha y hora
const [datePart, timePart] = input.split(" ");
const [day, month, year] = datePart.split("-");
const [hour, minute] = timePart.split(":");

// Crear objeto base (hora local)
const baseDate = new Date(`${year}-${month}-${day}T${hour}:${minute}:00`);

// Constante de un día en milisegundos
const oneDay = 24 * 60 * 60 * 1000;

// Fechas desplazadas
const startDate = new Date(baseDate.getTime() + oneDay);     // +1 día
const endDate = new Date(baseDate.getTime() + 4 * oneDay);   // +4 días

// Función para dar formato legible
function formatDate(date) {
  const dd = String(date.getDate()).padStart(2, '0');
  const mm = String(date.getMonth() + 1).padStart(2, '0'); // Meses van de 0 a 11
  const yyyy = date.getFullYear();
  const hh = String(date.getHours()).padStart(2, '0');
  const min = String(date.getMinutes()).padStart(2, '0');
  return `${dd}-${mm}-${yyyy} ${hh}:${min}`;
}

// Construcción del resultado
return [
  {
    json: {
      startDateTime: startDate.getTime(),
      endDateTime: endDate.getTime(),
      startDateTime_legible: formatDate(startDate),
      endDateTime_legible: formatDate(endDate)
    }
  }
];

const results = [];

function limpiarSaludoInicial(texto) {
  const normalizado = String(texto ?? "")
    .replace(/\r/g, "")
    .replace(/\\n/g, "\n")
    .replace(/\n{2,}/g, "\n\n")
    .trim();

  const patronesSaludo = [
    /^¡Hola,[\s\S]*?directora Luza:\s*\[Enlace\]\(https:\/\/drive\.google\.com\/file\/d\/[^)]+\)\.\s*/i,
    /^¡Hola,[\s\S]*?directora Luza:\s*\[Enlace\]\.\s*/i
  ];

  let textoLimpio = normalizado;
  let encontroSaludo = false;

  for (const regex of patronesSaludo) {
    if (regex.test(textoLimpio)) {
      textoLimpio = textoLimpio.replace(regex, "").trim();
      encontroSaludo = true;
      break;
    }
  }

  return {
    solo_saludo: encontroSaludo && textoLimpio.length === 0 ? 1 : 0,
    texto: textoLimpio
  };
}

for (const item of $input.all()) {
  const input = item.json.output || "";
  const resultado = limpiarSaludoInicial(input);

  const instance =
    item.json.body?.instance ??
    item.json.body?.data?.instance ??
    item.json.instance ??
    "";

  const remoteJid =
    item.json.body?.data?.key?.remoteJid ??
    item.json.data?.key?.remoteJid ??
    item.json.remoteJid ??
    "";

  results.push({
    json: {
      ...item.json,
      instance,
      remoteJid,
      solo_saludo: resultado.solo_saludo,
      parte: 1,
      total_partes: 1,
      mensaje: resultado.texto
    }
  });
}

return results;

// items es el array que recibe el nodo Code
return items.map(item => {
  // 1) Parsear la lista
  const fragments = JSON.parse(item.json.response);

  // 2) Limpiar cada fragmento
  const cleaned = fragments
    // Reemplaza cualquier aparición de [➡️ Received on 573234501828]"]
    .map(f => f.replace(/\[➡️ Received on 573234501828\]"?\]?/g, '').trim())
    // Filtra fragmentos vacíos
    .filter(f => f.length > 0);

  // 3) Unirlos en una sola cadena
  const cleanedResponse = cleaned.join('\n');

  // 4) Devolver el resultado limpio
  return {
    json: { cleanedResponse }
  };
});

const now = new Date().toLocaleString("es-CO", {
  timeZone: "America/Bogota",
  hour: "2-digit",
  minute: "2-digit",
  second: "2-digit",
  hour12: false
});

return [{
  json: {
    hora_actual: now
  }
}];

// Fecha/hora en Colombia
const nowBogota = new Date(
  new Date().toLocaleString("en-US", { timeZone: "America/Bogota" })
);

const hour = nowBogota.getHours();
const minutes = nowBogota.getMinutes();

let abierto = false;

// Horario todos los días: 11:00 – 20:00
const afterOpen = hour > 11 || (hour === 11 && minutes >= 0);
const beforeClose = hour < 20 || (hour === 20 && minutes === 0);

abierto = afterOpen && beforeClose;

return [{
  json: {
    abierto,
    hour,
    minutes,
    now_bogota: nowBogota.toISOString()
  }
}];

